const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 14);

const filtered = items.filter(item => {
  const pubDate = new Date(item.json.pubDate);
  return pubDate >= cutoff;
});

if (filtered.length === 0) {
  // Return a sentinel so downstream nodes know there's nothing to do
  return [{ json: { noUpdates: true } }];
}

return filtered;

return items.map(item => {
  return {
    json: {
      title: item.json.title,
      date: item.json.pubDate,
      content: item.json.contentSnippet || item.json.content || '',
      link: item.json.link
    }
  };
});

// Get the raw AI response content
const raw = $input.first().json.message?.content 
         || $input.first().json.content 
         || '{}';

// Strip markdown code fences (```json ... ``` or ``` ... ```)
let cleaned = raw.trim();
if (cleaned.startsWith('`')) {
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
}

let parsed;
try {
  parsed = typeof cleaned === 'object' ? cleaned : JSON.parse(cleaned);
} catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch(e2) { parsed = { hasRelevantUpdates: false, parseError: e2.message }; }
  } else {
    parsed = { hasRelevantUpdates: false, parseError: e.message };
  }
}

return [{ json: parsed }];

