// Get the email content from the Parse Client Email node
const emailData = $('Parse Client Email').first().json;

// Get contacts from the HTTP request
const contacts = $input.first().json.contacts || [];

// Filter: must have a valid email and not be DND
const validContacts = contacts.filter(c => c.email && !c.dnd);

// Return one item per contact with the email content merged in
return validContacts.map(c => ({
  json: {
    contactId: c.id,
    firstName: c.firstName || '',
    email: c.email,
    tags: c.tags || [],
    subject: emailData.subject,
    html_body: emailData.html_body,
    emailType: 'client'
  }
}));

// Get the email content from the Parse Prospect Email node
const emailData = $('Parse Prospect Email').first().json;

// When pagination is used, each page is a separate item - collect all contacts from all pages
const allContacts = [];
for (const item of $input.all()) {
  const contacts = item.json.contacts || [];
  allContacts.push(...contacts);
}

// Filter: must have a valid email and not be DND
const validProspects = allContacts.filter(c => c.email && !c.dnd);

// Return one item per contact with the email content merged in
return validProspects.map(c => ({
  json: {
    contactId: c.id,
    firstName: c.firstName || '',
    email: c.email,
    tags: c.tags || [],
    subject: emailData.subject,
    html_body: emailData.html_body,
    emailType: 'prospect'
  }
}));
